2	import type { Chat, ChatMessage } from "./types.js";
3	
4	// Simple in-memory store for chats
5	class ChatStore {
6	  private chats: Map<string, Chat> = new Map();
7	  private messages: Map<string, ChatMessage[]> = new Map();
8	
9	  createChat(title?: string): Chat {
10	    const id = uuidv4();
11	    const now = new Date().toISOString();
12	    const chat: Chat = {
13	      id,
