let capturedQueryParams: any = null;
let capturedMessages: string[] = [];

// Track what gets pushed to the MessageQueue by intercepting query()
vi.mock("@anthropic-ai/claude-agent-sdk", () => ({
  query: vi.fn((params: any) => {
    capturedQueryParams = params;

    // The prompt is a MessageQueue (async iterable). Consume it to capture messages.
    const iterable = params.prompt;

    // Return a mock async generator for the query output
    const mockOutput = (async function* () {
      // Read messages from the queue as they arrive
      for await (const msg of iterable) {
        capturedMessages.push(msg.message.content);
        // Yield a mock assistant response for each user message
        yield {
          type: "assistant",
          message: {
            content: [{ type: "text", text: `Echo: ${msg.message.content}` }],
          },
        };
      }
    })();

    // Return an object with Symbol.asyncIterator (matches Query interface)
    return {
      [Symbol.asyncIterator]: () => mockOutput[Symbol.asyncIterator](),
    };
  }),
}));

// Import after mock
const { AgentSession } = await import("../server/ai-client.js");

describe("AgentSession (V1 query with settingSources)", () => {
  beforeEach(() => {
    capturedQueryParams = null;
    capturedMessages = [];
  });

  it("calls query() with settingSources: ['project'] to load skills", () => {
    new AgentSession();
    expect(capturedQueryParams).toBeTruthy();
    expect(capturedQueryParams.options.settingSources).toEqual(["project"]);
  });

  it("uses sonnet model", () => {
    new AgentSession();
    expect(capturedQueryParams.options.model).toBe("sonnet");
  });

  it("uses bypassPermissions mode", () => {
    new AgentSession();
    expect(capturedQueryParams.options.permissionMode).toBe("bypassPermissions");
    expect(capturedQueryParams.options.allowDangerouslySkipPermissions).toBe(true);
  });

  it("sets maxTurns", () => {
    new AgentSession();
    expect(capturedQueryParams.options.maxTurns).toBe(50);
  });
});

describe("AgentSession.sendMessage (persona injection)", () => {
  beforeEach(() => {
    capturedMessages = [];
  });

  it("sends plain message when no persona", async () => {
    const session = new AgentSession();
    session.sendMessage("hello");
